<template>
    <div>
          <loader :isVisible="isLoading"></loader>
          <dynamic-form lang="en" ref="BarcodeReport" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>

          <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer  v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
      </div>
      </template>
<script>
import DataService from '../../services/DataService';
import ReportViewer from '../HrReport/ReportViewer.vue';
    export default {
        components: { ReportViewer },
        data() {
            return {
                usertype: null,
                companyleaderOwner:[],
                CompanyReportDDLTypes:[],
                ddlstage:[],
                dtFrom: null,
                dtTo: null,
                reportPath: null,
                parameter: [],
                RRBDOwnerId:null,
                LoggedOwnerId:null,
                mindate:null,
                Channelid:null,
                Stageid:null,
                FormSchema: [{
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "MultiSelectField",
                            label: this.$t("LeadOwners"),
                            name: "LeadOwner",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('LeadOwners'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Channels"),
                            name: "Channel",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Channels'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Stages"),
                            name: "Stages",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Stages'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },

                              {
                                  astype: "DateField",
                                  label: this.$t("DateFrom"),
                                  name: "dtFrom",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",

                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              {
                                  astype: "DateField",
                                  label: this.$t("DateTo"),
                                  name: "dtTO",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",

                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              
                    ],


                },


            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                },
            ],
            }
        },
        created: function () {
      
            this.usertype = this.GetUserInfo.UserType,
            this.GetCompanyLeadOwners();
            this.GetCompanyReportDDLTypes();
            this.GetDDLStages();
        },
        methods: {

            ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[0].Data[4].value = '';
        },
            GetCompanyLeadOwners: async function () {
                var vm = this;
                var url = `leadId=0&type=P&moduleName=CRM`
                await DataService.GetCompanyLeadOwners(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
            
            GetCompanyReportDDLTypes: async function () {
                var vm = this;
                var url = `type=CRM_CHANNELS&moduleName=CRM`;
                await DataService.GetCompanyReportDDLTypes(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            GetDDLStages: async function () {
                var vm = this;
                await DataService.GetDDLStages().then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[2].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
            onSubmit: function (e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                    var vm = this;
                    vm.isLoading=true;
                    vm.reportPath = '';  
                    vm.parameter=[];
                    var reportModel = {
                        reportName: "revenuereportbycrmdeal",
                        moduleName: "crm",
                        dateFrom: e.dtFrom,
                        dateTo: e.dtTO,
                        ownerIds:e.LeadOwner.length > 0 ? e.LeadOwner.map(item => item.value).join(",") : '',
                        channelids:e.Channel.length > 0 ? e.Channel.map(item => item.value).join(",") : '',
                        stageIds:e.Stages.length > 0 ? e.Stages.map(item => item.value).join(",") : '',
                    };
                    var objectPostString = JSON.stringify(reportModel);
                    DataService.ReportMain(objectPostString).then(response => {
                        vm.reportPath = response.data.ReportPath;
                        vm.parameter = response.data.parameters;
                    });
                    vm.isLoading=false;
                },
           
            onClear: function () {
                this.dtFrom=null;
                this.dtTo=null;
                this.parameter=[];
                this.reportPath=null;
                this.RRBDOwnerId=null;
                this.channelids=null;
                this.LoggedOwnerId=null;
                this.Stageid=null;
            },
            DependentDateObject: function () {
                this.dtTo = this.dtFrom;
                this.mindate=this.dtTo;
            }

        }
    }
    
    </script>